import React from "react";
import { AppBar, Toolbar,Typography, Button } from "@mui/material";
import colouriskologo from "../../items/Frame.png";
import { Chip,Avatar } from "@mui/material";
const Navbar = () => {
  return (
    <div className="navbar">
      <AppBar sx={{ background: "#FFFFFF" }} elevation={0}>
        <Toolbar style={{ justifyContent: "space-between", display: "flex" }}>
          <Avatar
            variant={"rounded"}
            alt="The image"
            src={colouriskologo}
            style={{
              width: 150,
              // height: 200,
              background: "FFFFFF",
              paddingLeft:22 
            }}
          />
          <Typography
              variant="h6"
              color={"black"}
              fontWeight={700}

              gutterBottom
              sx={{ textAlign: { md: "center", sx: "center" } }}
            >
              home
            </Typography>
            <Chip

            label="Contact"
            variant="outlined"
            // size="medium"
            sx={{
              mr: {md : 3},
              fontSize: { md: "1rem", xs: "0.8 rem" },
              px: 1,
              py: 3,
              borderRadius: "5000px",
              bgcolor: "#0B0B5A",
              color: "#FFFFFF",
              "&.MuiButtonBase-root:hover": {
                bgcolor: "#383838",
              },
              fontWeight : 600,
            }}
            onClick ={()=> window.open("http://delhijalboard.nic.in/notices/delhi-jal-board-djb")}
          />

        </Toolbar>
      </AppBar>
      <Toolbar />
    </div>
  );
};

export default Navbar;
